// Only react to heartbeat events — the status topic carries boot,
// OTA, credential-rotation and heartbeat events on the same channel.
if (!msg.payload || msg.payload.event !== 'heartbeat') return null;

// Clear previous timeout
if (context.timeout) {
    clearTimeout(context.timeout);
}

// Mark connected
node.status({fill:'green', shape:'dot', text:'Connected'});
node.send({payload: 'Connected'});

// Firmware heartbeat interval is 60 s — allow one missed beat before
// declaring the device offline (90 s > 60 s).
context.timeout = setTimeout(function() {
    node.status({fill:'red', shape:'ring', text:'Disconnected'});
    node.send({payload: 'Disconnected'});
}, 90000);

return null;

