return null;

// React to heartbeat AND boot events (boot is retained — gives us fw version on startup)
var event = msg.payload && msg.payload.event;
if (event !== "heartbeat" && event !== "boot") return null;

var uuid = msg.topic.split("/")[6];
if (!uuid) return null;

var timeouts = context.get("timeouts") || {};
if (timeouts[uuid]) clearTimeout(timeouts[uuid]);

node.status({ fill: "green", shape: "dot", text: uuid + " connected" });

timeouts[uuid] = setTimeout(function () {
    node.status({ fill: "red", shape: "ring", text: uuid + " disconnected" });
    node.send({ payload: "Disconnected", uuid: uuid, firmware_version: "", uptime_s: 0 });
}, 90000);
context.set("timeouts", timeouts);

msg.uuid             = uuid;
msg.firmware_version = msg.payload.firmware_version || "";
msg.uptime_s         = msg.payload.uptime_s || 0;
msg.payload          = "Connected";
return msg;

// Maintain a sorted list of unique UUIDs seen across all boots
var known = flow.get('knownUuids') || [];

if (msg.uuid && known.indexOf(msg.uuid) === -1) {
    known.push(msg.uuid);
    known.sort();
    flow.set('knownUuids', known);
}

// Output the full list as a plain newline-separated string
msg.payload = known.join('\n');
return msg;

if (!msg.payload || msg.payload.event !== 'heartbeat') return null;

if (context.timeout) {
    clearTimeout(context.timeout);
}

node.status({fill:'green', shape:'dot', text:'Connected'});
node.send([{payload: 'Connected'}, null]);

context.timeout = setTimeout(function() {
    node.status({fill:'red', shape:'ring', text:'Disconnected'});
    node.send([null, {payload: 'Disconnected'}]);
}, 90000);

return null;

msg.payload = "Device 'ESP32 - Alpha' (Office/Line/Cell NodeBox, ID: 32925666-155a-4a67-bf50-27c1ffa22b11) has gone offline. No heartbeat received for over 90 seconds.";
msg.systemPrompt = "You are an IoT monitoring assistant. When a device goes offline, respond with a 2-3 sentence alert summary and one actionable next step for the engineer. Be concise.";
return msg;

const names = {
  "32925666-155a-4a67-bf50-27c1ffa22b11": "ESP32-Alpha",
  "6cfe177f-92eb-4699-a9a6-8a3603aae175": "ESP32-Bravo",
  "79eb6f5f-2072-4904-b91d-50601f195c18": "ESP32-Charlie"
};
const uuid = msg.uuid;
if (!uuid) return null;
const devices = flow.get("hb_devices") || {};
const prev = devices[uuid] || {};
const connected = msg.payload === "Connected";
devices[uuid] = {
  name:     names[uuid] || uuid.slice(0,8) + "...",
  uuid:     uuid,
  status:   msg.payload,
  firmware: connected && msg.firmware_version ? msg.firmware_version : (prev.firmware || "—"),
  lastSeen: connected ? new Date().toLocaleString() : (prev.lastSeen || "Never")
};
flow.set("hb_devices", devices);
msg.payload = Object.values(devices).sort((a,b) => a.name.localeCompare(b.name));
return msg;

var uuids = flow.get("knownUuids") || [];
if (uuids.length === 0) {
    node.warn("No known devices yet — waiting for first heartbeat");
    return null;
}
uuids.forEach(function(uuid) {
    node.send({
        topic: "Enigma/JHBDev/Office/Line/Cell/ESP32NodeBox/" + uuid + "/cmd/ota_check",
        payload: ""
    });
});
return null;

var uuids = flow.get("knownUuids") || [];
if (uuids.length === 0) {
    node.warn("No known devices yet — waiting for first heartbeat");
    return null;
}
var msgs = [];
uuids.forEach(function(uuid) {
    msgs.push({
        topic: "Enigma/JHBDev/Office/Line/Cell/ESP32NodeBox/" + uuid + "/cmd/restart",
        payload: ""
    });
});
msgs.forEach(function(m) { node.send(m); });
return null;

var macs = Array.isArray(msg.payload) ? msg.payload : [msg.payload];
msg.payload = JSON.stringify({ macs: macs });
return msg;

var d = msg.payload;
return [
    { payload: d },
    { payload: parseFloat(d.dist_m) || 0,
      topic:  d.mac || "unknown",
      _label: (d.name ? d.name + " · " : "") + (d.mac || "unknown") },
    null
];

const NL = String.fromCharCode(10);
const beacons = (msg.payload && msg.payload.beacons) || msg.payload;
if (!Array.isArray(beacons)) { node.error('Expected beacons array', msg); return null; }
const ts = new Date().toISOString();
const lines = [];
if (!flow.get('csvHeaderWritten')) {
    flow.set('csvHeaderWritten', true);
    lines.push('timestamp,mac,name,rssi,dist_m,company_id');
}
beacons.forEach(function(b) {
    lines.push([ts, b.mac, b.name || '', b.rssi, b.dist_m, b.company_id].join(','));
});
msg.payload = lines.join(NL) + NL;
return msg;

var d = msg.payload;
if (!d || !d.mac) return null;
var devices = flow.get("tracked_devices") || {};
devices[d.mac] = { mac: d.mac, name: d.name || "", rssi: d.rssi, dist_m: d.dist_m };
flow.set("tracked_devices", devices);
msg.payload = { tracking: true, devices: Object.values(devices) };
return msg;

flow.set("tracked_devices", {});
node.send([{ payload: { tracking: false, devices: [] } }, { payload: "" }]);
return null;

// 1-D Kalman filter per MAC address
// Q — process noise: how fast the true distance can change.
//     Lower = assume device moves slowly, smoother output.
// R — measurement noise: how noisy a single BLE distance reading is.
//     Higher = trust measurements less, smoother but slower to react.
var Q = 0.1;
var R = 2.0;

var mac = msg.topic;
if (!mac) return msg;

var raw    = msg.payload;
var states = flow.get("kalman_states") || {};
var s      = states[mac] || { x: raw, p: 1.0 };  // seed with first reading

// Predict step
var xPred = s.x;
var pPred = s.p + Q;

// Update step
var K    = pPred / (pPred + R);           // Kalman gain
var xNew = xPred + K * (raw - xPred);     // corrected estimate
var pNew = (1 - K) * pPred;              // updated error covariance

states[mac] = { x: xNew, p: pNew };
flow.set("kalman_states", states);

msg.payload = Math.round(xNew * 10) / 10;
if (msg._label) msg.topic = msg._label;   // name · mac as chart series label
return msg;

flow.set("kalman_states", {});
msg.payload = [];
msg.action = "replace";
return msg;

var peers = (msg.payload && Array.isArray(msg.payload.peers))
            ? msg.payload.peers : [];
var disc = flow.get("espnow_discovered") || {};
var prevCount = Object.keys(disc).length;
peers.forEach(function(p) {
    if (p.mac) disc[p.mac] = { mac: p.mac, rssi: p.rssi, dist_m: p.dist_m };
});
flow.set("espnow_discovered", disc);
// Only send to peer table when a NEW peer has been discovered.
// This stops the table from re-rendering every 2 s while the user is
// selecting checkboxes, which would race with Vue's reactivity.
var newCount = Object.keys(disc).length;
if (newCount === prevCount) return null;
msg.payload = { peers: Object.values(disc) };
return msg;

flow.set('espnow_discovered', {});
msg.payload = { peers: [] };
return msg;

// [].concat() safely handles plain arrays, proxies, and single strings
var macs = [].concat(msg.payload || []).filter(function(m) {
    return typeof m === "string" && m.length > 0;
});
flow.set("espnow_tracked_macs", macs);

var disc = flow.get("espnow_discovered") || {};
var devices = macs.map(function(mac) { return disc[mac]; }).filter(Boolean);

// Output 0 → tracking indicator
// Output 1 → filter fn (seed the chart immediately with current peer data)
var seedMsg = (macs.length > 0)
    ? { payload: { peers: devices } }
    : null;

node.send([
    { payload: { tracking: macs.length > 0, devices: devices } },
    seedMsg
]);
return null;

var tracked = flow.get('espnow_tracked_macs') || [];
if (tracked.length === 0) return null;
var peers = (msg.payload && Array.isArray(msg.payload.peers))
            ? msg.payload.peers : [];
var msgs = [];
peers.forEach(function(p) {
    if (tracked.indexOf(p.mac) >= 0) {
        msgs.push({ payload: parseFloat(p.dist_m) || 0,
                    topic: p.mac, _label: p.mac });
    }
});
return msgs.length > 0 ? [msgs] : null;

var Q = 0.1;
var R = 2.0;
var mac = msg.topic;
if (!mac) return msg;
var raw    = msg.payload;
var states = flow.get('espnow_kalman_states') || {};
var s      = states[mac] || { x: raw, p: 1.0 };
var xPred  = s.x;
var pPred  = s.p + Q;
var K      = pPred / (pPred + R);
var xNew   = xPred + K * (raw - xPred);
var pNew   = (1 - K) * pPred;
states[mac] = { x: xNew, p: pNew };
flow.set('espnow_kalman_states', states);
msg.payload = Math.round(xNew * 10) / 10;
if (msg._label) msg.topic = msg._label;
return msg;

flow.set("espnow_tracked_macs", []);
node.send([
    { payload: { tracking: false, devices: [] } },
    { payload: [], action: "replace" }
]);
return null;

flow.set('espnow_kalman_states', {});
msg.payload = [];
msg.action = 'replace';
return msg;
